CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TYPE admin_role AS ENUM ('SUPER_ADMIN','ADMIN');
CREATE TYPE application_status AS ENUM ('PENDING','APPROVED','REJECTED');
CREATE TYPE contact_status AS ENUM ('NEW','READ','ARCHIVED');
CREATE TABLE admins(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),full_name varchar(150) NOT NULL,email varchar(320) NOT NULL,password_hash text NOT NULL,role admin_role NOT NULL,is_active boolean NOT NULL DEFAULT true,created_by uuid REFERENCES admins(id) ON DELETE SET NULL,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE UNIQUE INDEX admins_email_unique_ci ON admins(lower(email)); CREATE INDEX admins_role_active_idx ON admins(role,is_active);
CREATE TABLE refresh_tokens(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),admin_id uuid NOT NULL REFERENCES admins(id) ON DELETE CASCADE,token_hash char(64) NOT NULL UNIQUE,family_id uuid NOT NULL,replaced_by uuid REFERENCES refresh_tokens(id),expires_at timestamptz NOT NULL,revoked_at timestamptz,created_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX refresh_admin_family_idx ON refresh_tokens(admin_id,family_id);
CREATE TABLE expert_applications(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),full_name varchar(150) NOT NULL,email varchar(320) NOT NULL,phone varchar(40) NOT NULL,area_of_expertise varchar(150) NOT NULL,years_experience int NOT NULL CHECK(years_experience>=0 AND years_experience<=80),biography text NOT NULL,qualifications text NOT NULL,portfolio_url text,supporting_document_url text,status application_status NOT NULL DEFAULT 'PENDING',reviewed_by uuid REFERENCES admins(id) ON DELETE SET NULL,reviewed_at timestamptz,review_note text,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX expert_status_created_idx ON expert_applications(status,created_at DESC); CREATE INDEX expert_search_idx ON expert_applications(lower(full_name),lower(email));
CREATE TABLE membership_types(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),name varchar(120) NOT NULL UNIQUE,description text NOT NULL,requirements text NOT NULL,is_active boolean NOT NULL DEFAULT true,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX membership_types_active_idx ON membership_types(is_active);
CREATE TABLE membership_applications(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),membership_type_id uuid NOT NULL REFERENCES membership_types(id),full_name varchar(150) NOT NULL,email varchar(320) NOT NULL,phone varchar(40) NOT NULL,address text NOT NULL,motivation text NOT NULL,additional_information jsonb NOT NULL DEFAULT '{}',status application_status NOT NULL DEFAULT 'PENDING',reviewed_by uuid REFERENCES admins(id) ON DELETE SET NULL,reviewed_at timestamptz,review_note text,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX membership_app_status_type_idx ON membership_applications(status,membership_type_id,created_at DESC);
CREATE TABLE contact_messages(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),full_name varchar(150) NOT NULL,email varchar(320) NOT NULL,subject varchar(200) NOT NULL,message text NOT NULL,status contact_status NOT NULL DEFAULT 'NEW',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX contact_status_created_idx ON contact_messages(status,created_at DESC);
CREATE TABLE resources(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),title varchar(200) NOT NULL,description text NOT NULL,category varchar(100) NOT NULL,file_url text NOT NULL,original_filename text NOT NULL,mime_type varchar(150) NOT NULL,file_size bigint NOT NULL CHECK(file_size>0),is_published boolean NOT NULL DEFAULT false,uploaded_by uuid NOT NULL REFERENCES admins(id),created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX resources_published_created_idx ON resources(is_published,created_at DESC);
CREATE TABLE audit_logs(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),administrator_id uuid NOT NULL REFERENCES admins(id),action varchar(100) NOT NULL,entity_type varchar(80) NOT NULL,entity_id uuid,metadata jsonb NOT NULL DEFAULT '{}',created_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX audit_admin_created_idx ON audit_logs(administrator_id,created_at DESC); CREATE INDEX audit_entity_idx ON audit_logs(entity_type,entity_id);
